void mergeSort(Node** headRef) {
    if (*headRef == nullptr) {
        return;
    }

    Node* slow = *headRef;
    Node* fast = *headRef;

    while (fast->next != nullptr && fast->next->next != nullptr) {
        slow = slow->next;
        fast = fast->next->next;
    }

    Node* mid = slow->next;

    Node* midNext = mid->next;

    slow->next = nullptr;

    *headRef = mergeSort(&mid);
    mid->next = mergeSort(&(*headRef));
    return merge(&(*headRef), &mid);
}

bool merge(Node** headRef1, Node** headRef2) {
    if (*headRef1 == nullptr) {
        *headRef1 = *headRef2;
        return true;
    }

    if (*headRef2 == nullptr) {
        return true;
    }

    Node* head = new Node(*headRef1->value < *headRef2->value ? *headRef1 : *headRef2);

    Node* tail = head;

    Node* curr1 = *headRef1;

    Node* curr2 = *headRef2;

    while (curr1 != nullptr && curr2 != nullptr) {
        if (curr1->value < curr2->value) {
            tail->next = curr1;
            curr1 = curr1->next;
        } else {
            tail->next = curr2;
            curr2 = curr2->next;
        }

        tail = tail->next;
    }

    if (curr1 != nullptr) {
        tail->next = curr1;
    }

    if (curr2 != nullptr) {
        tail->next = curr2;
    }

    *headRef1 = head;

    return true;
}

